import { DEMO_MODE } from '@/lib/config';
import { getAgencyId } from '@/lib/session';
import { apiClient } from '@/lib/api/client';
import { mapBranch } from '@/lib/api/mappers';
import { mockBranches, mockStaffMembers } from '@/lib/mock-data';
import { staffMemberToManagerFields } from '@/lib/staff-utils';
import type { Branch } from '@/lib/types';
import type { BranchDto } from '@/lib/api/dto';

export const branchService = {
  async getBranches(agencyId?: string): Promise<Branch[]> {
    if (DEMO_MODE) return mockBranches;
    const id = agencyId ?? getAgencyId();
    const dtos = await apiClient.get<BranchDto[]>(`/agencies/${id}/branches`);
    return dtos.map(mapBranch);
  },

  async getBranch(branchId: string): Promise<Branch> {
    if (DEMO_MODE) return mockBranches.find(b => b.id === branchId) ?? mockBranches[0];
    const dto = await apiClient.get<BranchDto>(`/branches/${branchId}`);
    return mapBranch(dto);
  },

  async createBranch(agencyId: string, data: {
    name: string; code: string; city: string; country: string;
    street?: string; region?: string;
    openingHours?: string;
    managerId?: string;
    isHeadquarters?: boolean;
    status?: Branch['status'];
  }): Promise<Branch> {
    if (DEMO_MODE) {
      const manager = data.managerId
        ? mockStaffMembers.find(m => m.id === data.managerId)
        : undefined;
      const id = `BRN-${String(mockBranches.length + 1).padStart(3, '0')}`;
      const branch: Branch = {
        id,
        agencyId: 'AGN-001',
        name: data.name,
        address: data.street ?? '',
        city: data.city,
        isHeadquarters: data.isHeadquarters ?? false,
        status: data.status ?? 'OPEN',
        openingHours: data.openingHours ?? 'Lun–Sam 08h00–18h00',
        deliverersCount: 0,
        createdAt: new Date().toISOString().slice(0, 10),
        ...staffMemberToManagerFields(manager),
      };
      if (manager && data.managerId) {
        manager.branchId = id;
        manager.branchName = data.name;
        if (manager.role === 'AGENCY_MANAGER') manager.role = 'BRANCH_MANAGER';
      }
      mockBranches.push(branch);
      return branch;
    }

    const dto = await apiClient.post<BranchDto>(`/agencies/${agencyId}/branches`, {
      name: data.name,
      code: data.code,
      address: {
        city: data.city,
        country: data.country,
        street: data.street,
        region: data.region,
      },
    });
    const branch = mapBranch(dto);
    if (data.managerId) {
      await this.assignManager(branch.id, data.managerId);
      return this.getBranch(branch.id);
    }
    return branch;
  },

  async updateBranch(branchId: string, data: Partial<Branch>): Promise<void> {
    if (DEMO_MODE) {
      const idx = mockBranches.findIndex(b => b.id === branchId);
      if (idx >= 0) mockBranches[idx] = { ...mockBranches[idx], ...data };
      return;
    }
    await apiClient.patch(`/branches/${branchId}`, {
      name: data.name,
      address: {
        city: data.city,
        country: 'CM',
        street: data.address,
      },
    });
  },

  async assignManager(branchId: string, managerId: string): Promise<void> {
    if (DEMO_MODE) {
      const branch = mockBranches.find(b => b.id === branchId);
      const manager = mockStaffMembers.find(m => m.id === managerId);
      if (!branch) return;
      mockStaffMembers.forEach(m => {
        if (m.branchId === branchId && m.id !== managerId) {
          m.branchId = undefined;
          m.branchName = undefined;
        }
      });
      if (manager) {
        manager.branchId = branchId;
        manager.branchName = branch.name;
        if (manager.role === 'AGENCY_MANAGER') manager.role = 'BRANCH_MANAGER';
        Object.assign(branch, staffMemberToManagerFields(manager));
      }
      return;
    }
    await apiClient.patch(
      `/branches/${branchId}/manager?managerId=${encodeURIComponent(managerId)}`,
      {},
    );
  },

  async clearManager(branchId: string): Promise<void> {
    if (DEMO_MODE) {
      const branch = mockBranches.find(b => b.id === branchId);
      if (!branch) return;
      mockStaffMembers.forEach(m => {
        if (m.branchId === branchId) {
          m.branchId = undefined;
          m.branchName = undefined;
        }
      });
      branch.managerId = undefined;
      branch.managerName = undefined;
      branch.managerEmail = undefined;
      branch.managerPhone = undefined;
      return;
    }
    await apiClient.delete(`/branches/${branchId}/manager`);
  },

  async closeBranch(branchId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.delete(`/branches/${branchId}`);
  },

  async temporarilyCloseBranch(branchId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(
      `/branches/${branchId}/status?status=TEMPORARILY_CLOSED`,
      {},
    );
  },

  async reopenBranch(branchId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/branches/${branchId}/status?status=OPEN`, {});
  },
};
